103→/// Generate a random integer, biased toward boundary values.
104→fn generate_int(rng: &mut impl Rng) -> Value {
105→    let choice: u8 = rng.random_range(0..10);
106→    let n = match choice {
107→        0 => 0,
108→        1 => 1,
109→        2 => -1,
110→        3 => i64::MAX,
111→        4 => i64::MIN,
112→        _ => rng.random_range(-1000..=1000),
113→    };
114→    json!(n)
115→}
116→
117→/// Generate a random float, biased toward boundary values.
118→///
119→/// Includes integer values in the distribution since TypeScript's `number`
120→/// type covers both integers and floats.
121→fn generate_float(rng: &mut impl Rng) -> Value {
122→    let choice: u8 = rng.random_range(0..12);
123→    let n: f64 = match choice {
124→        0 => 0.0,
125→        1 => 1.0,
126→        2 => -1.0,
127→        3 => 0.5,
128→        4 => -0.5,
129→        // Include some integer values to cover integer-like branches (e.g. n % 2 === 0)
130→        5 => rng.random_range(-100..=100) as f64,
131→        6 => 2.0,
132→        7 => -2.0,
133→        8 => 10.0,
134→        _ => rng.random_range(-1000.0..1000.0),
135→    };
136→    json!(n)
137→}
138→
139→/// Generate a random string from a small vocabulary plus random characters.
140→fn generate_string(rng: &mut impl Rng) -> Value {
141→    let choice: u8 = rng.random_range(0..10);
142→    let s = match choice {
143→        0 => String::new(),
144→        1 => "hello".to_string(),
145→        2 => "test".to_string(),
146→        3 => " ".to_string(),
147→        4 => "0".to_string(),
148→        5 => "true".to_string(),
149→        6 => "null".to_string(),
150→        _ => {
151→            let len = rng.random_range(1..=20);
152→            (0..len)
153→                .map(|_| rng.random_range(b'a'..=b'z') as char)
154→                .collect()
155→        }
156→    };
157→    json!(s)
158→}
159→
160→/// Generate a random array with bounded length, biased toward small sizes.
161→///
162→/// Most real bugs appear at boundary lengths (0, 1, 2, 3), so we heavily
163→/// favor those over larger sizes. The distribution:
164→/// - 25% chance of length 0 (empty array)
165→/// - 25% chance of length 1 (single element)
166→/// - 20% chance of length 2
167→/// - 15% chance of length 3
168→/// - 15% chance of length 4-5 (larger arrays, less common in bug-triggering)
169→fn generate_array(
170→    element: &TypeInfo,
171→    rng: &mut impl Rng,
172→    caps: Option<&FrontendCapabilities>,
173→) -> Value {
174→    let len = generate_bounded_array_length(rng);
175→    let items: Vec<Value> = (0..len)
176→        .map(|_| generate_random_value(element, rng, caps))
177→        .collect();
178→    json!(items)
179→}
180→
181→/// Generate an array length biased toward small boundary values (0-3).
182→fn generate_bounded_array_length(rng: &mut impl Rng) -> usize {
183→    let choice: u8 = rng.random_range(0..20);
184→    match choice {
185→        0..5 => 0,   // 25%: empty
186→        5..10 => 1,  // 25%: single element
187→        10..14 => 2, // 20%: two elements
188→        14..17 => 3, // 15%: three elements
189→        _ => rng.random_range(4..=5), // 15%: larger
190→    }
191→}
192→
193→/// Generate a random object with the specified fields.
194→fn generate_object(
195→    fields: &[(String, TypeInfo)],
196→    rng: &mut impl Rng,
197→    caps: Option<&FrontendCapabilities>,
198→) -> Value {
199→    let mut obj = serde_json::Map::new();
200→    for (name, typ) in fields {
201→        obj.insert(name.clone(), generate_random_value(typ, rng, caps));
202→    }
203→    Value::Object(obj)
204→}
205→
206→/// Pick a random variant from a union type.
207→fn generate_union(
208→    variants: &[TypeInfo],
209→    rng: &mut impl Rng,
210→    caps: Option<&FrontendCapabilities>,
211→) -> Value {
212→    if variants.is_empty() {
213→        return Value::Null;
214→    }
215→    let idx = rng.random_range(0..variants.len());
216→    generate_random_value(&variants[idx], rng, caps)
217→}
218→
219→/// Generate null ~30% of the time, otherwise generate the inner type.
220→fn generate_nullable(
221→    inner: &TypeInfo,
222→    rng: &mut impl Rng,
223→    caps: Option<&FrontendCapabilities>,
224→) -> Value {
225→    if rng.random_range(0..10) < 3 {
226→        Value::Null
227→    } else {
228→        generate_random_value(inner, rng, caps)
229→    }
230→}
