178→    fn round_trip<T: Serialize + for<'de> Deserialize<'de> + PartialEq + std::fmt::Debug>(
179→        value: &T,
180→    ) {
181→        let json = serde_json::to_string(value).expect("serialize");
182→        let deserialized: T = serde_json::from_str(&json).expect("deserialize");
183→        assert_eq!(*value, deserialized, "round-trip failed for json: {json}");
184→    }
